def get_category_by_id(category_id: int):
    return next((c for c in CATEGORIES if c["id"] == category_id), None)

def get_category_by_slug(slug: str):
    return next((c for c in CATEGORIES if c["slug"] == slug), None)

def get_product_by_id(product_id: int):
    return next((p for p in PRODUCTS if p["id"] == product_id), None)

def get_product_by_sku(sku: str):
    return next((p for p in PRODUCTS if p["sku"] == sku), None)

def get_reviews_for_product(product_id: int):
    return [r for r in REVIEWS if r["product_id"] == product_id]

def avg_rating_for_product(product_id: int):
    rs = get_reviews_for_product(product_id)
    if not rs:
        return None
    return sum(r["rating"] for r in rs) / len(rs)

