class Query(ObjectType):
    # Products
    product = Field(ProductType, id=Argument(Int), sku=Argument(String))
    products = List(
        ProductType,
        category_id=Argument(Int),
        category_slug=Argument(String),
        search=Argument(String),
        in_stock=Argument(Boolean),
        limit=Argument(Int),
        offset=Argument(Int),
    )

    # Categories
    category = Field(CategoryType, id=Argument(Int), slug=Argument(String))
    categories = List(CategoryType, limit=Argument(Int), offset=Argument(Int))

    # Reviews
    review = Field(ReviewType, id=Argument(Int, required=True))
    reviews = List(
        ReviewType,
        product_id=Argument(Int),
        user_id=Argument(Int),
        username=Argument(String),
        min_rating=Argument(Int),
        verified_purchase=Argument(Boolean),
        limit=Argument(Int),
        offset=Argument(Int),
    )

    def resolve_product(root, info, id=None, sku=None):
        if id is not None:
            return get_product_by_id(id)
        if sku is not None:
            return get_product_by_sku(sku)
        return None

    def resolve_products(
        root,
        info,
        category_id=None,
        category_slug=None,
        search=None,
        in_stock=None,
        limit=None,
        offset=None,
    ):
        items = list(PRODUCTS)

        if category_slug is not None and category_id is None:
            cat = get_category_by_slug(category_slug)
            category_id = cat["id"] if cat else -1

        if category_id is not None:
            items = [p for p in items if p["category_id"] == category_id]

        if in_stock is not None:
            items = [p for p in items if p["in_stock"] == in_stock]

        if search:
            s = search.strip().lower()
            items = [
                p
                for p in items
                if s in (p.get("name") or "").lower()
                or s in (p.get("sku") or "").lower()
                or s in (p.get("description") or "").lower()
            ]

        if offset:
            items = items[offset:]
        if limit is not None:
            items = items[:limit]
        return items

    def resolve_category(root, info, id=None, slug=None):
        if id is not None:
            return get_category_by_id(id)
        if slug is not None:
            return get_category_by_slug(slug)
        return None

    def resolve_categories(root, info, limit=None, offset=None):
        items = list(CATEGORIES)
        if offset:
            items = items[offset:]
        if limit is not None:
            items = items[:limit]
        return items

    def resolve_review(root, info, id):
        return next((r for r in REVIEWS if r["id"] == id), None)

    def resolve_reviews(
        root,
        info,
        product_id=None,
        user_id=None,
        username=None,
        min_rating=None,
        verified_purchase=None,
        limit=None,
        offset=None,
    ):
        items = list(REVIEWS)

        if product_id is not None:
            items = [r for r in items if r["product_id"] == product_id]
        if user_id is not None:
            items = [r for r in items if r["user_id"] == user_id]
        if username is not None:
            u = username.strip().lower()
            items = [r for r in items if (r.get("username") or "").lower() == u]
        if min_rating is not None:
            items = [r for r in items if r["rating"] >= min_rating]
        if verified_purchase is not None:
            items = [r for r in items if r["verified_purchase"] == verified_purchase]

        if offset:
            items = items[offset:]
        if limit is not None:
            items = items[:limit]
        return items

schema = Schema(query=Query, auto_camelcase=False)

